import { useCurrentTheme } from '../../../../core/hooks/useCurrentTheme.js';
import { BrightnessFilter } from '../BrightnessFilter.js';
import {
  MARKER_LIGHT_BRIGHTNESS,
  MARKER_DARK_BRIGHTNESS,
} from './markers/constants.js';

interface ThresholdBrightnessFilterProps {
  id: string;
}

export const ThresholdBrightnessFilter = ({
  id,
}: ThresholdBrightnessFilterProps) => {
  const theme = useCurrentTheme();
  const brightnessSlope =
    theme === 'dark' ? MARKER_DARK_BRIGHTNESS : MARKER_LIGHT_BRIGHTNESS;

  return <BrightnessFilter id={id} slope={brightnessSlope} />;
};
